package store

import (
	"context"
	"testing"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

// MockStore implements Store interface for testing
type MockStore struct {
	sandboxes        map[string]*types.SandboxInfo
	expiryIndex      map[string]float64
	activityIndex    map[string]float64
	pingErr          error
	getErr           error
	storeErr         error
	updateErr        error
	deleteErr        error
	listExpiredErr   error
	listInactiveErr  error
	updateActivityErr error
}

func NewMockStore() *MockStore {
	return &MockStore{
		sandboxes:     make(map[string]*types.SandboxInfo),
		expiryIndex:   make(map[string]float64),
		activityIndex: make(map[string]float64),
	}
}

func (m *MockStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *MockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	sandbox, ok := m.sandboxes[sessionID]
	if !ok {
		return nil, ErrNotFound
	}
	return sandbox, nil
}

func (m *MockStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if m.storeErr != nil {
		return m.storeErr
	}
	if sandbox == nil {
		return ErrNotFound
	}
	m.sandboxes[sandbox.SessionID] = sandbox
	m.expiryIndex[sandbox.SessionID] = float64(sandbox.ExpiresAt.Unix())
	m.activityIndex[sandbox.SessionID] = float64(time.Now().Unix())
	return nil
}

func (m *MockStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if m.updateErr != nil {
		return m.updateErr
	}
	if sandbox == nil {
		return ErrNotFound
	}
	if _, ok := m.sandboxes[sandbox.SessionID]; !ok {
		return ErrNotFound
	}
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *MockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	delete(m.sandboxes, sessionID)
	delete(m.expiryIndex, sessionID)
	delete(m.activityIndex, sessionID)
	return nil
}

func (m *MockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if m.listExpiredErr != nil {
		return nil, m.listExpiredErr
	}
	var result []*types.SandboxInfo
	for id, expiry := range m.expiryIndex {
		if expiry <= float64(before.Unix()) {
			if sandbox, ok := m.sandboxes[id]; ok {
				result = append(result, sandbox)
				if len(result) >= int(limit) {
					break
				}
			}
		}
	}
	return result, nil
}

func (m *MockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if m.listInactiveErr != nil {
		return nil, m.listInactiveErr
	}
	var result []*types.SandboxInfo
	for id, activity := range m.activityIndex {
		if activity <= float64(before.Unix()) {
			if sandbox, ok := m.sandboxes[id]; ok {
				result = append(result, sandbox)
				if len(result) >= int(limit) {
					break
				}
			}
		}
	}
	return result, nil
}

func (m *MockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if m.updateActivityErr != nil {
		return m.updateActivityErr
	}
	if _, ok := m.sandboxes[sessionID]; !ok {
		return ErrNotFound
	}
	if at.IsZero() {
		at = time.Now()
	}
	m.activityIndex[sessionID] = float64(at.Unix())
	return nil
}

func (m *MockStore) Close() error {
	return nil
}

func TestMockStore_Ping(t *testing.T) {
	tests := []struct {
		name    string
		pingErr error
		wantErr bool
	}{
		{
			name:    "successful ping",
			pingErr: nil,
			wantErr: false,
		},
		{
			name:    "ping error",
			pingErr: ErrNotFound,
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := NewMockStore()
			m.pingErr = tt.pingErr
			err := m.Ping(context.Background())
			if (err != nil) != tt.wantErr {
				t.Errorf("Ping() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestMockStore_GetSandboxBySessionID(t *testing.T) {
	tests := []struct {
		name      string
		sessionID string
		setup     func(*MockStore)
		wantErr   bool
		wantNil   bool
	}{
		{
			name:      "existing sandbox",
			sessionID: "test-session-1",
			setup: func(m *MockStore) {
				m.sandboxes["test-session-1"] = &types.SandboxInfo{
					SessionID: "test-session-1",
					SandboxID: "sandbox-1",
				}
			},
			wantErr: false,
			wantNil: false,
		},
		{
			name:      "non-existing sandbox",
			sessionID: "test-session-2",
			setup:     func(m *MockStore) {},
			wantErr:   true,
			wantNil:   true,
		},
		{
			name:      "get error",
			sessionID: "test-session-3",
			setup: func(m *MockStore) {
				m.getErr = ErrNotFound
			},
			wantErr: true,
			wantNil: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := NewMockStore()
			tt.setup(m)
			sandbox, err := m.GetSandboxBySessionID(context.Background(), tt.sessionID)
			if (err != nil) != tt.wantErr {
				t.Errorf("GetSandboxBySessionID() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if tt.wantNil && sandbox != nil {
				t.Errorf("GetSandboxBySessionID() expected nil, got %v", sandbox)
			}
			if !tt.wantNil && sandbox == nil {
				t.Errorf("GetSandboxBySessionID() expected non-nil, got nil")
			}
		})
	}
}

func TestMockStore_StoreSandbox(t *testing.T) {
	tests := []struct {
		name    string
		sandbox *types.SandboxInfo
		setup   func(*MockStore)
		wantErr bool
	}{
		{
			name: "valid sandbox",
			sandbox: &types.SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				ExpiresAt: time.Now().Add(time.Hour),
			},
			setup:   func(m *MockStore) {},
			wantErr: false,
		},
		{
			name:    "nil sandbox",
			sandbox: nil,
			setup:   func(m *MockStore) {},
			wantErr: true,
		},
		{
			name: "store error",
			sandbox: &types.SandboxInfo{
				SessionID: "session-2",
				SandboxID: "sandbox-2",
				ExpiresAt: time.Now().Add(time.Hour),
			},
			setup: func(m *MockStore) {
				m.storeErr = ErrNotFound
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := NewMockStore()
			tt.setup(m)
			err := m.StoreSandbox(context.Background(), tt.sandbox)
			if (err != nil) != tt.wantErr {
				t.Errorf("StoreSandbox() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestMockStore_UpdateSandbox(t *testing.T) {
	tests := []struct {
		name    string
		sandbox *types.SandboxInfo
		setup   func(*MockStore)
		wantErr bool
	}{
		{
			name: "update existing sandbox",
			sandbox: &types.SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				Status:    "running",
			},
			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{
					SessionID: "session-1",
					SandboxID: "sandbox-1",
					Status:    "pending",
				}
			},
			wantErr: false,
		},
		{
			name: "update non-existing sandbox",
			sandbox: &types.SandboxInfo{
				SessionID: "session-2",
				SandboxID: "sandbox-2",
			},
			setup:   func(m *MockStore) {},
			wantErr: true,
		},
		{
			name:    "nil sandbox",
			sandbox: nil,
			setup:   func(m *MockStore) {},
			wantErr: true,
		},
		{
			name: "update error",
			sandbox: &types.SandboxInfo{
				SessionID: "session-3",
				SandboxID: "sandbox-3",
			},
			setup: func(m *MockStore) {
				m.sandboxes["session-3"] = &types.SandboxInfo{}
				m.updateErr = ErrNotFound
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := NewMockStore()
			tt.setup(m)
			err := m.UpdateSandbox(context.Background(), tt.sandbox)
			if (err != nil) != tt.wantErr {
				t.Errorf("UpdateSandbox() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestMockStore_DeleteSandboxBySessionID(t *testing.T) {
	tests := []struct {
		name      string
		sessionID string
		setup     func(*MockStore)
		wantErr   bool
	}{
		{
			name:      "delete existing sandbox",
			sessionID: "session-1",
			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{SessionID: "session-1"}
			},
			wantErr: false,
		},
		{
			name:      "delete non-existing sandbox",
			sessionID: "session-2",
			setup:     func(m *MockStore) {},
			wantErr:   false,
		},
		{
			name:      "delete error",
			sessionID: "session-3",
			setup: func(m *MockStore) {
				m.deleteErr = ErrNotFound
			},
			wantErr: true,
