			if (err != nil) != tt.wantErr {
				t.Errorf("DeleteSandboxBySessionID() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestMockStore_ListExpiredSandboxes(t *testing.T) {
	now := time.Now()
	tests := []struct {
		name   string
		before time.Time
		limit  int64
		setup  func(*MockStore)
		want   int
	}{
		{
			name:   "list expired sandboxes",
			before: now,
			limit:  10,
			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{SessionID: "session-1", ExpiresAt: now.Add(-time.Hour)}
				m.sandboxes["session-2"] = &types.SandboxInfo{SessionID: "session-2", ExpiresAt: now.Add(time.Hour)}
				m.expiryIndex["session-1"] = float64(now.Add(-time.Hour).Unix())
				m.expiryIndex["session-2"] = float64(now.Add(time.Hour).Unix())
			},
			want: 1,
		},
		{
			name:   "respect limit",
			before: now.Add(time.Hour),
			limit:  1,
			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{SessionID: "session-1", ExpiresAt: now.Add(-time.Hour)}
				m.sandboxes["session-2"] = &types.SandboxInfo{SessionID: "session-2", ExpiresAt: now.Add(-time.Hour)}
				m.expiryIndex["session-1"] = float64(now.Add(-time.Hour).Unix())
				m.expiryIndex["session-2"] = float64(now.Add(-time.Hour).Unix())
			},
			want: 1,
		},
		{
			name:   "empty list",
			before: now.Add(-time.Hour),
			limit:  10,
			setup:  func(m *MockStore) {},
			want:   0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := NewMockStore()
			tt.setup(m)
			sandboxes, err := m.ListExpiredSandboxes(context.Background(), tt.before, tt.limit)
			if err != nil {
				t.Errorf("ListExpiredSandboxes() unexpected error = %v", err)
				return
			}
			if len(sandboxes) != tt.want {
				t.Errorf("ListExpiredSandboxes() returned %d sandboxes, want %d", len(sandboxes), tt.want)
			}
		})
	}
}

