func TestMockStore_UpdateSessionLastActivity(t *testing.T) {
	tests := []struct {
		name      string
		sessionID string
		at        time.Time
		setup     func(*MockStore)
		wantErr   bool
	}{
		{
			name:      "update existing session",
			sessionID: "session-1",
			at:        time.Now(),
			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{SessionID: "session-1"}
			},
			wantErr: false,
		},
		{
			name:      "update non-existing session",
			sessionID: "session-2",
