			setup: func(m *MockStore) {
				m.sandboxes["session-1"] = &types.SandboxInfo{SessionID: "session-1"}
			},
			wantErr: false,
		},
		{
			name:      "update error",
			sessionID: "session-3",
			at:        time.Now(),
			setup: func(m *MockStore) {
				m.sandboxes["session-3"] = &types.SandboxInfo{SessionID: "session-3"}
