func TestStorage_Singleton(t *testing.T) {
	// Save and clear environment
	oldStoreType := os.Getenv("STORE_TYPE")
	oldRedisAddr := os.Getenv("REDIS_ADDR")
	oldRedisPassword := os.Getenv("REDIS_PASSWORD")
	oldRedisPasswordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")

	defer func() {
		_ = os.Setenv("STORE_TYPE", oldStoreType)
		_ = os.Setenv("REDIS_ADDR", oldRedisAddr)
		_ = os.Setenv("REDIS_PASSWORD", oldRedisPassword)
		_ = os.Setenv("REDIS_PASSWORD_REQUIRED", oldRedisPasswordRequired)
	}()

	// Test cases for Storage() function
	tests := []struct {
		name        string
		storeType   string
		redisAddr   string
		redisPass   string
		passRequired string
		wantPanic   bool
	}{
		{
			name:        "default store type is redis",
			storeType:   "",
			redisAddr:   "localhost:6379",
			redisPass:   "test",
			passRequired: "",
			wantPanic:   true, // Will panic because no Redis server
		},
		{
			name:        "explicit redis type",
			storeType:   "redis",
			redisAddr:   "localhost:6379",
			redisPass:   "test",
			passRequired: "",
			wantPanic:   true,
		},
		{
			name:        "valkey type",
			storeType:   "valkey",
			redisAddr:   "localhost:6379",
			redisPass:   "test",
			passRequired: "",
			wantPanic:   true,
		},
		{
			name:        "valkey type case insensitive",
			storeType:   "VALKEY",
			redisAddr:   "localhost:6379",
			redisPass:   "test",
			passRequired: "",
			wantPanic:   true,
		},
		{
			name:        "unsupported store type panics",
			storeType:   "unsupported",
			redisAddr:   "localhost:6379",
