func TestNewRedisStore(t *testing.T) {
	tests := []struct {
		name    string
		envVars map[string]string
		wantErr bool
		errMsg  string
	}{
		{
			name:    "missing REDIS_ADDR",
			envVars: map[string]string{},
			wantErr: true,
			errMsg:  "REDIS_ADDR environment variable is not set",
		},
		{
			name: "password required by default",
			envVars: map[string]string{
				"REDIS_ADDR": "localhost:6379",
			},
			wantErr: true,
			errMsg:  "REDIS_PASSWORD is required",
		},
		{
			name: "password not required when explicitly disabled",
			envVars: map[string]string{
				"REDIS_ADDR":              "localhost:6379",
				"REDIS_PASSWORD_REQUIRED": "false",
			},
			wantErr: true, // Still fails because no Redis server
		},
		{
			name: "valid configuration",
			envVars: map[string]string{
				"REDIS_ADDR":     "localhost:6379",
				"REDIS_PASSWORD": "testpass",
			},
			wantErr: true, // Still fails because no Redis server
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Clear environment
			for _, key := range []string{"REDIS_ADDR", "REDIS_PASSWORD", "REDIS_PASSWORD_REQUIRED"} {
				_ = os.Unsetenv(key)
			}

			// Set test environment variables
			for key, value := range tt.envVars {
				_ = os.Setenv(key, value)
			}

			// Cleanup
			defer func() {
				for key := range tt.envVars {
					_ = os.Unsetenv(key)
				}
			}()

			store, err := NewRedisStore()
			if (err != nil) != tt.wantErr {
				t.Errorf("NewRedisStore() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if tt.errMsg != "" && err != nil {
				if err.Error() != tt.errMsg {
					t.Errorf("NewRedisStore() error message = %v, want %v", err.Error(), tt.errMsg)
				}
			}
			if store != nil {
				_ = store.Close()
			}
		})
	}
}

