import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	valkeySessionKeyPrefix       = "session:"
	valkeySessionExpiryKey       = "session:expiry"
	valkeySessionLastActivityKey = "session:last_activity"
)

// ValkeyStore implements Store interface using Valkey
type ValkeyStore struct {
	client valkey.Client
}

// NewValkeyStore creates a new Valkey store
func NewValkeyStore() (*ValkeyStore, error) {
	// Get address from environment
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = os.Getenv("REDIS_ADDR")
	}
	if addr == "" {
		return nil, errors.New("VALKEY_ADDR or REDIS_ADDR environment variable is not set")
	}

	// Parse multiple addresses (comma-separated)
	addresses := strings.Split(addr, ",")
	for i := range addresses {
		addresses[i] = strings.TrimSpace(addresses[i])
	}

	// Get password from environment
	password := os.Getenv("VALKEY_PASSWORD")
	if password == "" {
		password = os.Getenv("REDIS_PASSWORD")
	}

	// Check if password is required
	passwordRequired := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED")) != "false"
	if passwordRequired && password == "" {
		return nil, errors.New("VALKEY_PASSWORD is required")
	}

	// Parse optional client flags
	disableCache := parseBoolEnv("VALKEY_DISABLE_CACHE", false)
	forceSingle := parseBoolEnv("VALKEY_FORCE_SINGLE", false)

	// Build client options
	opts := valkey.ClientOption{
		InitAddress: addresses,
		Password:    password,
	}

	if disableCache {
		opts.DisableCache = true
	}

	if forceSingle {
		opts.ForceSingleClient = true
	}

	client, err := valkey.NewClient(opts)
	if err != nil {
		return nil, fmt.Errorf("failed to create valkey client: %w", err)
	}

	return &ValkeyStore{client: client}, nil
}

// parseBoolEnv parses a boolean value from environment variable
func parseBoolEnv(key string, defaultValue bool) bool {
	value := strings.ToLower(os.Getenv(key))
	if value == "" {
		return defaultValue
	}
	parsed, err := strconv.ParseBool(value)
	if err != nil {
		return defaultValue
	}
	return parsed
}

func (v *ValkeyStore) Ping(ctx context.Context) error {
	return v.client.Do(ctx, v.client.B().Ping().Build()).Error()
}

func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := valkeySessionKeyPrefix + sessionID
	data, err := v.client.Do(ctx, v.client.B().Get().Key(key).Build()).ToString()
	if err != nil {
		if strings.Contains(err.Error(), "nil") || strings.Contains(err.Error(), "Nil") {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("expiresAt is required")
	}

	key := valkeySessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use transaction for atomic operations
	commands := []valkey.Completed{
		v.client.B().Set().Key(key).Value(string(data)).Build(),
		v.client.B().Zadd().Key(valkeySessionExpiryKey).ScoreMember().
			ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build(),
		v.client.B().Zadd().Key(valkeySessionLastActivityKey).ScoreMember().
			ScoreMember(float64(time.Now().Unix()), sandbox.SessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}

	return nil
}

func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}

	key := valkeySessionKeyPrefix + sandbox.SessionID
	exists, err := v.client.Do(ctx, v.client.B().Exists().Key(key).Build()).AsBool()
	if err != nil {
		return err
	}
	if !exists {
		return errors.New("key not exists")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	return v.client.Do(ctx, v.client.B().Set().Key(key).Value(string(data)).Build()).Error()
}

func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := valkeySessionKeyPrefix + sessionID

	commands := []valkey.Completed{
		v.client.B().Del().Key(key).Build(),
		v.client.B().Zrem().Key(valkeySessionExpiryKey).Member(sessionID).Build(),
		v.client.B().Zrem().Key(valkeySessionLastActivityKey).Member(sessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}

	return nil
}

func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return v.listSandboxesByScore(ctx, valkeySessionExpiryKey, 0, before.Unix(), limit)
}

func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return v.listSandboxesByScore(ctx, valkeySessionLastActivityKey, 0, before.Unix(), limit)
}

func (v *ValkeyStore) listSandboxesByScore(ctx context.Context, key string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	ids, err := v.client.Do(ctx, v.client.B().Zrangebyscore().Key(key).Min(fmt.Sprintf("%d", min)).Max(fmt.Sprintf("%d", max)).
		Limit(0, limit).Build()).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, ids)
}

func (v *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, ids []string) ([]*types.SandboxInfo, error) {
	if len(ids) == 0 {
		return nil, nil
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(ids))
	for _, id := range ids {
		sandbox, err := v.GetSandboxBySessionID(ctx, id)
		if err != nil {
			if err == ErrNotFound {
				// Skip orphaned entries
				klog.Warningf("Sandbox %s not found in store, skipping", id)
				continue
			}
			klog.Warningf("Failed to get sandbox %s: %v", id, err)
			continue
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is required")
	}

	if at.IsZero() {
		at = time.Now()
	}

	// Verify session exists
	key := valkeySessionKeyPrefix + sessionID
	exists, err := v.client.Do(ctx, v.client.B().Exists().Key(key).Build()).AsBool()
	if err != nil {
		return err
	}
	if !exists {
		return ErrNotFound
	}

	return v.client.Do(ctx, v.client.B().Zadd().Key(valkeySessionLastActivityKey).ScoreMember().
		ScoreMember(float64(at.Unix()), sessionID).Build()).Error()
}

func (v *ValkeyStore) Close() error {
	v.client.Close()
	return nil
}
